document.addEventListener('DOMContentLoaded', () => {
  const sidebar = document.querySelector('[data-admin-sidebar]');
  const menuButton = document.querySelector('[data-admin-menu]');
  menuButton?.addEventListener('click', () => {
    sidebar?.classList.toggle('is-open');
  });
  document.addEventListener('keydown', (event) => {
    if (event.key === 'Escape') {
      sidebar?.classList.remove('is-open');
      document.querySelector('[data-notification-center]')?.classList.remove('is-open');
      document.querySelectorAll('.modal.is-open').forEach((modal) => modal.classList.remove('is-open'));
    }
  });
  document.querySelectorAll('.modal').forEach((modal) => {
    modal.addEventListener('click', (event) => {
      if (event.target === modal) {
        modal.classList.remove('is-open');
      }
    });
  });
  const searchInput = document.querySelector('[data-crm-search]');
  const leadCards = document.querySelectorAll('[data-lead-card]');
  const settingsTabs = document.querySelectorAll('[data-settings-tab]');
  const settingsPanels = document.querySelectorAll('[data-settings-panel]');
  const settingsStatus = document.querySelector('[data-settings-status]');
  const notificationCenter = document.querySelector('[data-notification-center]');
  const notificationToggle = document.querySelector('[data-notification-toggle]');
  const notificationCount = document.querySelector('[data-notification-count]');
  const updateNotificationCount = (count) => {
    if (!notificationCount) {
      return;
    }
    notificationCount.textContent = String(count);
    notificationCount.hidden = Number(count) <= 0;
  };
  const persistNotificationAction = async (action, notificationId = null) => {
    const formData = new FormData();
    formData.append('action', action);
    formData.append('_csrf_token', window.GALVAO_CSRF || '');
    if (notificationId) {
      formData.append('notification_id', notificationId);
    }
    const response = await fetch('ajax/notifications.php', {
      method: 'POST',
      body: formData,
      headers: { Accept: 'application/json' },
    });
    const result = await response.json();
    if (!response.ok || !result.success) {
      throw new Error(result.message || 'Nao foi possivel processar a notificacao.');
    }
    updateNotificationCount(result.unread_count || 0);
    return result;
  };
  notificationToggle?.addEventListener('click', () => {
    const isOpen = notificationCenter?.classList.toggle('is-open');
    notificationToggle.setAttribute('aria-expanded', isOpen ? 'true' : 'false');
  });
  document.addEventListener('click', (event) => {
    if (notificationCenter && !notificationCenter.contains(event.target)) {
      notificationCenter.classList.remove('is-open');
      notificationToggle?.setAttribute('aria-expanded', 'false');
    }
  });
  document.querySelectorAll('[data-notification-mark-all]').forEach((button) => {
    button.addEventListener('click', async () => {
      try {
        await persistNotificationAction('mark_all_read');
        document.querySelectorAll('.notification-item, .notification-timeline-item').forEach((item) => item.classList.remove('is-unread'));
        document.querySelector('[data-notification-page-count]') && (document.querySelector('[data-notification-page-count]').textContent = '0');
      } catch (error) {
        button.textContent = error.message;
      }
    });
  });
  document.addEventListener('click', async (event) => {
    const button = event.target.closest('[data-notification-read]');
    if (!button) {
      return;
    }
    const item = button.closest('[data-notification-id]');
    const id = Number(item?.dataset.notificationId || 0);
    item?.classList.remove('is-unread');
    if (id <= 0) {
      return;
    }
    try {
      await persistNotificationAction('mark_read', String(id));
    } catch (error) {
      item?.classList.add('is-unread');
    }
  });
  searchInput?.addEventListener('input', () => {
    const query = searchInput.value.trim().toLowerCase();
  leadCards.forEach((card) => {
      card.hidden = query !== '' && !card.textContent.toLowerCase().includes(query);
    });
  });
  settingsTabs.forEach((tab) => {
    tab.addEventListener('click', () => {
      const target = tab.dataset.settingsTab;
      settingsTabs.forEach((item) => item.classList.toggle('is-active', item === tab));
      settingsPanels.forEach((panel) => {
        panel.classList.toggle('is-active', panel.dataset.settingsPanel === target);
      });
    });
  });
  document.querySelectorAll('[data-settings-form]').forEach((form) => {
    form.addEventListener('submit', async (event) => {
      event.preventDefault();
      const formData = new FormData(form);
      formData.append('_csrf_token', window.GALVAO_CSRF || '');
      if (settingsStatus) {
        settingsStatus.querySelector('strong').textContent = 'Salvando';
        settingsStatus.querySelector('span').textContent = 'Aplicando configuracoes com seguranca...';
      }
      try {
        const response = await fetch('ajax/settings.php', {
          method: 'POST',
          body: formData,
          headers: { Accept: 'application/json' },
        });
        const result = await response.json();
        if (!response.ok || !result.success) {
          throw new Error(result.message || 'Nao foi possivel salvar.');
        }
        if (settingsStatus) {
          settingsStatus.querySelector('strong').textContent = 'Salvo';
          settingsStatus.querySelector('span').textContent = result.message;
        }
        if (form.querySelector('[name="action"]')?.value === 'create_user') {
          window.setTimeout(() => window.location.reload(), 700);
        }
      } catch (error) {
        if (settingsStatus) {
          settingsStatus.querySelector('strong').textContent = 'Atencao';
          settingsStatus.querySelector('span').textContent = error.message;
        }
      }
    });
  });
  const backupsPage = document.querySelector('[data-backups-page]');
  if (backupsPage) {
    const status = backupsPage.querySelector('[data-backup-status]');
    const setBackupStatus = (title, message) => {
      if (!status) {
        return;
      }
      status.querySelector('strong').textContent = title;
      status.querySelector('span').textContent = message;
    };
    const postBackupAction = async (formData) => {
      formData.append('_csrf_token', window.GALVAO_CSRF || '');
      const response = await fetch('ajax/backups.php', {
        method: 'POST',
        body: formData,
        headers: { Accept: 'application/json' },
      });
      const result = await response.json();
      if (!response.ok || !result.success) {
        throw new Error(result.message || 'Nao foi possivel processar o backup.');
      }
      return result;
    };
    backupsPage.querySelector('[data-backup-form]')?.addEventListener('submit', async (event) => {
      event.preventDefault();
      const form = event.currentTarget;
      const button = form.querySelector('button[type="submit"]');
      const formData = new FormData(form);
      formData.set('include_uploads', form.querySelector('[name="include_uploads"]')?.checked ? '1' : '0');
      setBackupStatus('Gerando', 'Compactando banco e arquivos com seguranca...');
      button.disabled = true;
      try {
        await postBackupAction(formData);
        setBackupStatus('Concluido', 'Backup criado. Atualizando a lista...');
        window.setTimeout(() => window.location.reload(), 900);
      } catch (error) {
        setBackupStatus('Atencao', error.message);
      } finally {
        button.disabled = false;
      }
    });
    backupsPage.querySelector('[data-backup-cleanup]')?.addEventListener('click', async (event) => {
      const formData = new FormData();
      formData.append('action', 'cleanup');
      setBackupStatus('Limpando', 'Aplicando politica de retencao...');
      event.currentTarget.disabled = true;
      try {
        await postBackupAction(formData);
        setBackupStatus('Retencao aplicada', 'Backups antigos foram removidos quando necessario.');
        window.setTimeout(() => window.location.reload(), 900);
      } catch (error) {
        setBackupStatus('Atencao', error.message);
      } finally {
        event.currentTarget.disabled = false;
      }
    });
  }
  const queuePage = document.querySelector('[data-queue-page]');
  if (queuePage) {
    const status = queuePage.querySelector('[data-queue-status]');
    const setQueueStatus = (message, isError = false) => {
      if (!status) {
        return;
      }
      status.textContent = message;
      status.hidden = false;
      status.classList.toggle('is-error', isError);
    };
    const postQueueAction = async (payload) => {
      const formData = new FormData();
      Object.entries(payload).forEach(([key, value]) => formData.append(key, value));
      formData.append('_csrf_token', window.GALVAO_CSRF || '');
      const response = await fetch('ajax/queue.php', {
        method: 'POST',
        body: formData,
        headers: { Accept: 'application/json' },
      });
      const result = await response.json();
      if (!response.ok || !result.success) {
        throw new Error(result.message || 'Nao foi possivel atualizar a fila.');
      }
      return result;
    };
    queuePage.querySelector('[data-queue-run]')?.addEventListener('click', async (event) => {
      const button = event.currentTarget;
      button.disabled = true;
      setQueueStatus('Worker em execucao. Processando ate 3 jobs...');
      try {
        const result = await postQueueAction({ action: 'run_once', limit: '3' });
        const processed = result.data?.processed?.length || 0;
        setQueueStatus(processed ? `${processed} job(ns) processado(s). Atualizando painel...` : 'Nenhum job pendente neste momento.');
        window.setTimeout(() => window.location.reload(), 900);
      } catch (error) {
        setQueueStatus(error.message, true);
      } finally {
        button.disabled = false;
      }
    });
    queuePage.querySelector('[data-queue-notifications]')?.addEventListener('click', async (event) => {
      const button = event.currentTarget;
      button.disabled = true;
      setQueueStatus('Criando job de notificacoes internas...');
      try {
        await postQueueAction({ action: 'enqueue_notifications' });
        setQueueStatus('Notificacoes enfileiradas.');
        window.setTimeout(() => window.location.reload(), 700);
      } catch (error) {
        setQueueStatus(error.message, true);
      } finally {
        button.disabled = false;
      }
    });
    queuePage.addEventListener('click', async (event) => {
      const retry = event.target.closest('[data-queue-retry]');
      const cancel = event.target.closest('[data-queue-cancel]');
      const actionButton = retry || cancel;
      if (!actionButton) {
        return;
      }
      actionButton.disabled = true;
      setQueueStatus(retry ? 'Reenfileirando job...' : 'Cancelando job...');
      try {
        await postQueueAction({
          action: retry ? 'retry' : 'cancel',
          job_id: retry?.dataset.queueRetry || cancel?.dataset.queueCancel || '',
        });
        setQueueStatus('Fila atualizada.');
        window.setTimeout(() => window.location.reload(), 700);
      } catch (error) {
        setQueueStatus(error.message, true);
      } finally {
        actionButton.disabled = false;
      }
    });
  }
  const visualBank = document.querySelector('[data-visual-bank]');
  if (visualBank) {
    const visualCards = [...visualBank.querySelectorAll('[data-visual-card]')];
    const visualSearch = visualBank.querySelector('[data-visual-search]');
    const visualFilters = [...visualBank.querySelectorAll('[data-visual-filter]')];
    const visualHistory = visualBank.querySelector('[data-visual-history]');
    const visualModal = visualBank.querySelector('[data-visual-modal]');
    const compareModal = visualBank.querySelector('[data-compare-modal]');
    const normalizeFilter = (value) => String(value || '').trim().toLowerCase().replaceAll('-', ' ');
    const applyVisualFilters = () => {
      const query = normalizeFilter(visualSearch?.value);
      const activeFilters = Object.fromEntries(visualFilters.map((filter) => [filter.dataset.visualFilter, normalizeFilter(filter.value)]));
      visualCards.forEach((card) => {
        const matchesSearch = !query || normalizeFilter(card.dataset.search).includes(query);
        const matchesSurface = !activeFilters.surface || normalizeFilter(card.dataset.surface).includes(activeFilters.surface);
        const matchesNeighborhood = !activeFilters.neighborhood || normalizeFilter(card.dataset.neighborhood).includes(activeFilters.neighborhood);
        const matchesTag = !activeFilters.tag || normalizeFilter(card.dataset.tags).includes(activeFilters.tag);
        const matchesDirt = !activeFilters.dirt || normalizeFilter(card.dataset.dirt).includes(activeFilters.dirt);
        const matchesDifficulty = !activeFilters.difficulty || normalizeFilter(card.dataset.difficulty).includes(activeFilters.difficulty);
        card.hidden = !(matchesSearch && matchesSurface && matchesNeighborhood && matchesTag && matchesDirt && matchesDifficulty);
      });
    };
    visualSearch?.addEventListener('input', applyVisualFilters);
    visualFilters.forEach((filter) => filter.addEventListener('change', applyVisualFilters));
    visualBank.querySelector('[data-visual-clear]')?.addEventListener('click', () => {
      if (visualSearch) {
        visualSearch.value = '';
      }
      visualFilters.forEach((filter) => {
        filter.value = '';
      });
      applyVisualFilters();
    });
    visualBank.addEventListener('click', (event) => {
      const card = event.target.closest('[data-visual-card]');
      if (card && visualHistory) {
        visualHistory.innerHTML = `<strong>${escapeHtml(card.dataset.title || 'Imagem tecnica')}</strong><p>${escapeHtml(card.dataset.history || '').replaceAll('\n', '<br>')}</p>`;
      }
      const openButton = event.target.closest('[data-visual-open]');
      if (openButton && card && visualModal) {
        const image = visualModal.querySelector('[data-visual-modal-image]');
        const title = visualModal.querySelector('[data-visual-modal-title]');
        const client = visualModal.querySelector('[data-visual-modal-client]');
        const meta = visualModal.querySelector('[data-visual-modal-meta]');
        if (card.dataset.fullImage) {
          image.src = card.dataset.fullImage;
          image.hidden = false;
        } else {
          image.removeAttribute('src');
          image.hidden = true;
        }
        title.textContent = card.dataset.title || 'Imagem tecnica';
        client.textContent = card.dataset.client || 'Cliente';
        meta.textContent = card.dataset.meta || '';
        visualModal.classList.add('is-open');
      }
      const compareButton = event.target.closest('[data-compare-open]');
      if (compareButton && compareModal) {
        const before = compareModal.querySelector('[data-compare-before]');
        const after = compareModal.querySelector('[data-compare-after]');
        const title = compareModal.querySelector('[data-compare-title]');
        const client = compareModal.querySelector('[data-compare-client]');
        before.hidden = !compareButton.dataset.before;
        after.hidden = !compareButton.dataset.after;
        if (compareButton.dataset.before) {
          before.src = compareButton.dataset.before;
        }
        if (compareButton.dataset.after) {
          after.src = compareButton.dataset.after;
        }
        title.textContent = compareButton.dataset.title || 'Comparador antes e depois';
        client.textContent = compareButton.dataset.client || 'Cliente';
        compareModal.classList.add('is-open');
      }
    });
    visualBank.querySelector('[data-visual-close]')?.addEventListener('click', () => visualModal?.classList.remove('is-open'));
    visualBank.querySelector('[data-compare-close]')?.addEventListener('click', () => compareModal?.classList.remove('is-open'));
  }
  const productsPage = document.querySelector('[data-products-page]');
  if (productsPage) {
    const productCards = [...productsPage.querySelectorAll('[data-product-card]')];
    const productSearch = productsPage.querySelector('[data-product-search]');
    const productCategory = productsPage.querySelector('[data-product-category]');
    const productStatus = productsPage.querySelector('[data-product-status]');
    const usageModal = productsPage.querySelector('[data-product-usage-modal]');
    const usageForm = productsPage.querySelector('[data-product-usage-form]');
    const setProductStatus = (message) => {
      if (!productStatus) {
        return;
      }
      productStatus.hidden = false;
      productStatus.textContent = message;
      window.setTimeout(() => {
        productStatus.hidden = true;
      }, 1600);
    };
    const filterProducts = () => {
      const query = String(productSearch?.value || '').trim().toLowerCase();
      const category = String(productCategory?.value || '').trim().toLowerCase();
      productCards.forEach((card) => {
        const matchesQuery = !query || String(card.dataset.search || '').includes(query);
        const matchesCategory = !category || String(card.dataset.category || '') === category;
        card.hidden = !(matchesQuery && matchesCategory);
      });
    };
    productSearch?.addEventListener('input', filterProducts);
    productCategory?.addEventListener('change', filterProducts);
    productsPage.querySelector('[data-product-new]')?.addEventListener('click', () => {
      productsPage.querySelector('[data-product-form]')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    });
    productsPage.querySelector('[data-product-form]')?.addEventListener('submit', async (event) => {
      event.preventDefault();
      const formData = new FormData(event.currentTarget);
      formData.append('_csrf_token', window.GALVAO_CSRF || '');
      setProductStatus('Salvando produto...');
      try {
        const response = await fetch('ajax/products.php', {
          method: 'POST',
          body: formData,
          headers: { Accept: 'application/json' },
        });
        const result = await response.json();
        if (!response.ok || !result.success) {
          throw new Error(result.message || 'Nao foi possivel salvar.');
        }
        setProductStatus(result.message);
        window.setTimeout(() => window.location.reload(), 700);
      } catch (error) {
        setProductStatus(error.message);
      }
    });
    productsPage.addEventListener('click', (event) => {
      const button = event.target.closest('[data-product-apply]');
      if (!button || !usageModal || !usageForm) {
        return;
      }
      usageForm.querySelector('[data-usage-product-id]').value = button.dataset.productId || '';
      usageForm.querySelector('[data-usage-product-title]').textContent = button.dataset.productName || 'Registrar produto';
      usageForm.querySelector('[data-usage-dilution]').value = button.dataset.productDilution || '';
      usageModal.classList.add('is-open');
    });
    productsPage.querySelector('[data-product-usage-close]')?.addEventListener('click', () => usageModal?.classList.remove('is-open'));
    usageForm?.addEventListener('submit', async (event) => {
      event.preventDefault();
      const formData = new FormData(usageForm);
      formData.append('_csrf_token', window.GALVAO_CSRF || '');
      setProductStatus('Registrando aplicacao...');
      try {
        const response = await fetch('ajax/products.php', {
          method: 'POST',
          body: formData,
          headers: { Accept: 'application/json' },
        });
        const result = await response.json();
        if (!response.ok || !result.success) {
          throw new Error(result.message || 'Nao foi possivel registrar.');
        }
        usageModal?.classList.remove('is-open');
        setProductStatus(result.message);
        window.setTimeout(() => window.location.reload(), 700);
      } catch (error) {
        setProductStatus(error.message);
      }
    });
  }
  const tagModal = document.querySelector('[data-tag-modal]');
  const tagForm = document.querySelector('[data-tag-form]');
  const tagList = document.querySelector('[data-tag-list]');
  const escapeHtml = (value) => String(value)
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#039;');
  document.querySelector('[data-tag-create]')?.addEventListener('click', () => {
    tagModal?.classList.add('is-open');
  });
  document.querySelector('[data-tag-close]')?.addEventListener('click', () => {
    tagModal?.classList.remove('is-open');
  });
  tagForm?.addEventListener('submit', (event) => {
    event.preventDefault();
    const formData = new FormData(tagForm);
    const tagName = String(formData.get('tag_name') || '').trim();
    const tagColor = String(formData.get('tag_color') || '#C8A95B');
    if (!tagName) {
      return;
    }
    const card = document.createElement('article');
    card.className = 'card tag-manager-card';
    card.style.setProperty('--tag-color', tagColor);
    card.innerHTML = `
      <div>
        <span class="tag-color-dot"></span>
        <strong>${escapeHtml(tagName)}</strong>
        <p>0 clientes vinculados</p>
      </div>
      <div class="tag-manager-card__actions">
        <button class="btn btn--ghost" type="button" data-tag-edit>Editar</button>
        <button class="btn btn--ghost" type="button" data-tag-delete>Excluir</button>
      </div>
    `;
    tagList?.prepend(card);
    tagForm.reset();
    tagModal?.classList.remove('is-open');
  });
  tagList?.addEventListener('click', (event) => {
    const button = event.target.closest('[data-tag-delete]');
    if (button) {
      button.closest('.tag-manager-card')?.remove();
    }
  });
  const submitNoteForm = async (form) => {
    const formData = new FormData(form);
    if (!formData.has('action')) {
      formData.append('action', 'create');
    }
    formData.append('_csrf_token', window.GALVAO_CSRF || '');
    const response = await fetch('ajax/notes.php', {
      method: 'POST',
      body: formData,
      headers: { Accept: 'application/json' },
    });
    const result = await response.json();
    if (!response.ok || !result.success) {
      throw new Error(result.message || 'Nao foi possivel salvar a observacao.');
    }
    return result;
  };
  document.querySelector('[data-comment-form]')?.addEventListener('submit', async (event) => {
    event.preventDefault();
    const form = event.currentTarget;
    const textarea = form.querySelector('textarea');
    const list = document.querySelector('[data-comment-list]');
    const body = textarea.value.trim();
    const title = form.querySelector('[name="title"]')?.value.trim() || 'Equipe';
    if (!body) {
      return;
    }
    try {
      await submitNoteForm(form);
      const item = document.createElement('article');
      item.className = 'comment-item';
      item.innerHTML = `<strong>${escapeHtml(title)}</strong><p>${escapeHtml(body)}</p><small>Agora</small>`;
      list?.prepend(item);
      form.reset();
    } catch (error) {
      const item = document.createElement('article');
      item.className = 'comment-item';
      item.innerHTML = `<strong>Atencao</strong><p>${escapeHtml(error.message)}</p><small>Agora</small>`;
      list?.prepend(item);
    }
  });
  const notesPage = document.querySelector('[data-notes-page]');
  if (notesPage) {
    const noteSearch = notesPage.querySelector('[data-note-search]');
    const noteTypeFilter = notesPage.querySelector('[data-note-type-filter]');
    const noteCards = [...notesPage.querySelectorAll('[data-note-card]')];
    const noteStatus = notesPage.querySelector('[data-note-status]');
    const setNoteStatus = (message) => {
      if (!noteStatus) {
        return;
      }
      noteStatus.hidden = false;
      noteStatus.textContent = message;
      window.setTimeout(() => {
        noteStatus.hidden = true;
      }, 1600);
    };
    const filterNotes = () => {
      const query = String(noteSearch?.value || '').trim().toLowerCase();
      const type = String(noteTypeFilter?.value || '').trim();
      noteCards.forEach((card) => {
        const matchesQuery = !query || String(card.dataset.search || '').includes(query);
        const matchesType = !type || card.dataset.noteType === type;
        card.hidden = !(matchesQuery && matchesType);
      });
    };
    noteSearch?.addEventListener('input', filterNotes);
    noteTypeFilter?.addEventListener('change', filterNotes);
    notesPage.querySelector('[data-note-form]')?.addEventListener('submit', async (event) => {
      event.preventDefault();
      setNoteStatus('Salvando observacao...');
      try {
        const result = await submitNoteForm(event.currentTarget);
        setNoteStatus(result.message);
        window.setTimeout(() => window.location.reload(), 700);
      } catch (error) {
        setNoteStatus(error.message);
      }
    });
    notesPage.addEventListener('click', async (event) => {
      const button = event.target.closest('[data-note-pin]');
      if (!button) {
        return;
      }
      const card = button.closest('[data-note-card]');
      const id = Number(card?.dataset.noteId || 0);
      card?.classList.toggle('is-pinned');
      button.textContent = card?.classList.contains('is-pinned') ? 'Desfixar' : 'Fixar';
      if (id <= 0) {
        return;
      }
      const formData = new FormData();
      formData.append('action', 'toggle_pin');
      formData.append('note_id', String(id));
      formData.append('_csrf_token', window.GALVAO_CSRF || '');
      try {
        const response = await fetch('ajax/notes.php', {
          method: 'POST',
          body: formData,
          headers: { Accept: 'application/json' },
        });
        const result = await response.json();
        if (!response.ok || !result.success) {
          throw new Error(result.message || 'Nao foi possivel fixar.');
        }
        setNoteStatus(result.message);
      } catch (error) {
        setNoteStatus(error.message);
      }
    });
  }
  document.querySelector('[data-copy-whatsapp]')?.addEventListener('click', async (event) => {
    const phone = event.currentTarget.dataset.copyWhatsapp;
    try {
      await navigator.clipboard.writeText(phone);
      event.currentTarget.textContent = 'Telefone copiado';
      window.setTimeout(() => {
        event.currentTarget.textContent = 'Copiar telefone';
      }, 1600);
    } catch (error) {
      event.currentTarget.textContent = phone;
    }
  });
  const kanbanBoard = document.querySelector('[data-kanban-board]');
  const kanbanSearch = document.querySelector('[data-kanban-search]');
  const kanbanStatus = document.querySelector('[data-kanban-status]');
  let draggedCard = null;
  const updateKanbanCounts = () => {
    document.querySelectorAll('[data-kanban-column]').forEach((column) => {
      const count = column.querySelectorAll('[data-kanban-card]:not([hidden])').length;
      const counter = column.querySelector('[data-kanban-count]');
      if (counter) {
        counter.textContent = String(count);
      }
    });
  };
  const persistKanbanMove = async (card, column) => {
    const cards = [...column.querySelectorAll('[data-kanban-card]')];
    const formData = new FormData();
    formData.append('card_id', card.dataset.cardId);
    formData.append('column_id', column.closest('[data-kanban-column]').dataset.kanbanColumn);
    formData.append('position', String(cards.indexOf(card)));
    formData.append('_csrf_token', window.GALVAO_CSRF || '');
    if (kanbanStatus) {
      kanbanStatus.hidden = false;
      kanbanStatus.textContent = 'Atualizando etapa...';
    }
    try {
      await fetch('ajax/kanban-update.php', {
        method: 'POST',
        body: formData,
        headers: { Accept: 'application/json' },
      });
      if (kanbanStatus) {
        kanbanStatus.textContent = 'Etapa atualizada';
      }
    } catch (error) {
      if (kanbanStatus) {
        kanbanStatus.textContent = 'Movimento local. Backend preparado.';
      }
    }
    window.setTimeout(() => {
      if (kanbanStatus) {
        kanbanStatus.hidden = true;
      }
    }, 1400);
  };
  const getDropTarget = (dropzone, pointerY) => {
    const cards = [...dropzone.querySelectorAll('[data-kanban-card]:not(.is-dragging)')];
    return cards.reduce((closest, child) => {
      const box = child.getBoundingClientRect();
      const offset = pointerY - box.top - box.height / 2;
      if (offset < 0 && offset > closest.offset) {
        return { offset, element: child };
      }
      return closest;
    }, { offset: Number.NEGATIVE_INFINITY, element: null }).element;
  };
  kanbanBoard?.addEventListener('dragstart', (event) => {
    const card = event.target.closest('[data-kanban-card]');
    if (!card) {
      return;
    }
    draggedCard = card;
    card.classList.add('is-dragging');
    event.dataTransfer.effectAllowed = 'move';
    event.dataTransfer.setData('text/plain', card.dataset.cardId);
  });
  kanbanBoard?.addEventListener('dragend', () => {
    draggedCard?.classList.remove('is-dragging');
    draggedCard = null;
    document.querySelectorAll('[data-kanban-dropzone]').forEach((zone) => zone.classList.remove('is-over'));
    updateKanbanCounts();
  });
  kanbanBoard?.addEventListener('dragover', (event) => {
    const dropzone = event.target.closest('[data-kanban-dropzone]');
    if (!dropzone || !draggedCard) {
      return;
    }
    event.preventDefault();
    dropzone.classList.add('is-over');
    const target = getDropTarget(dropzone, event.clientY);
    if (target) {
      dropzone.insertBefore(draggedCard, target);
    } else {
      dropzone.appendChild(draggedCard);
    }
  });
  kanbanBoard?.addEventListener('dragleave', (event) => {
    const dropzone = event.target.closest('[data-kanban-dropzone]');
    if (dropzone && !dropzone.contains(event.relatedTarget)) {
      dropzone.classList.remove('is-over');
    }
  });
  kanbanBoard?.addEventListener('drop', (event) => {
    const dropzone = event.target.closest('[data-kanban-dropzone]');
    if (!dropzone || !draggedCard) {
      return;
    }
    event.preventDefault();
    dropzone.classList.remove('is-over');
    persistKanbanMove(draggedCard, dropzone);
    updateKanbanCounts();
  });
  kanbanSearch?.addEventListener('input', () => {
    const query = kanbanSearch.value.trim().toLowerCase();
    document.querySelectorAll('[data-kanban-card]').forEach((card) => {
      card.hidden = query !== '' && !card.textContent.toLowerCase().includes(query);
    });
    updateKanbanCounts();
  });
  updateKanbanCounts();
  const calendarPage = document.querySelector('[data-calendar-page]');
  if (calendarPage) {
    const viewButtons = calendarPage.querySelectorAll('[data-calendar-view]');
    const panels = calendarPage.querySelectorAll('[data-calendar-panel]');
    const heading = calendarPage.querySelector('[data-calendar-heading]');
    const modal = calendarPage.querySelector('[data-event-modal]');
    const form = calendarPage.querySelector('[data-event-form]');
    const status = calendarPage.querySelector('[data-calendar-status]');
    const categoryColors = {
      visit: '#D4AF37',
      service: '#72C78F',
      follow_up: '#73A7FF',
      preventive: '#C8A95B',
    };
    let draggedEvent = null;
    const setCalendarStatus = (message) => {
      if (!status) {
        return;
      }
      status.textContent = message;
      status.hidden = false;
      window.setTimeout(() => {
        status.hidden = true;
      }, 1400);
    };
    const openEventModal = (eventButton = null) => {
      const title = modal.querySelector('[data-event-modal-title]');
      const fields = {
        id: form.querySelector('[data-event-field="id"]'),
        title: form.querySelector('[data-event-field="title"]'),
        date: form.querySelector('[data-event-field="date"]'),
        time: form.querySelector('[data-event-field="time"]'),
        category: form.querySelector('[data-event-field="category"]'),
        client: form.querySelector('[data-event-field="client"]'),
        location: form.querySelector('[data-event-field="location"]'),
      };
      form.reset();
      if (eventButton) {
        title.textContent = 'Editar evento';
        fields.id.value = eventButton.dataset.eventId || '';
        fields.title.value = eventButton.dataset.eventTitle || '';
        fields.date.value = eventButton.dataset.eventDate || '';
        fields.time.value = eventButton.dataset.eventTime || '';
        fields.category.value = eventButton.dataset.eventCategory || 'visit';
        fields.client.value = eventButton.dataset.eventClient || '';
        fields.location.value = eventButton.dataset.eventLocation || '';
      } else {
        title.textContent = 'Novo evento';
        fields.date.value = '2026-05-07';
        fields.time.value = '09:00';
        fields.category.value = 'visit';
      }
      modal.classList.add('is-open');
    };
    const persistCalendarEvent = async (payload) => {
      const formData = new FormData();
      Object.entries(payload).forEach(([key, value]) => formData.append(key, value));
      formData.append('_csrf_token', window.GALVAO_CSRF || '');
      try {
        await fetch('ajax/calendar-event.php', {
          method: 'POST',
          body: formData,
          headers: { Accept: 'application/json' },
        });
        setCalendarStatus('Evento atualizado');
      } catch (error) {
        setCalendarStatus('Evento local. Backend preparado.');
      }
    };
    const createEventButton = (payload) => {
      const button = document.createElement('button');
      button.className = 'calendar-event';
      button.type = 'button';
      button.draggable = true;
      button.dataset.calendarEvent = '';
      button.dataset.eventId = payload.event_id || String(Date.now());
      button.dataset.eventDate = payload.date;
      button.dataset.eventTitle = payload.title;
      button.dataset.eventTime = payload.time;
      button.dataset.eventClient = payload.client || '';
      button.dataset.eventLocation = payload.location || '';
      button.dataset.eventCategory = payload.category || 'visit';
      button.style.setProperty('--event-color', categoryColors[payload.category] || '#D4AF37');
      button.innerHTML = `<strong>${escapeHtml(payload.time)}</strong><span>${escapeHtml(payload.title)}</span>`;
      return button;
    };
    const updateEventButton = (button, payload) => {
      button.dataset.eventDate = payload.date;
      button.dataset.eventTitle = payload.title;
      button.dataset.eventTime = payload.time;
      button.dataset.eventClient = payload.client || '';
      button.dataset.eventLocation = payload.location || '';
      button.dataset.eventCategory = payload.category || 'visit';
      button.style.setProperty('--event-color', categoryColors[payload.category] || '#D4AF37');
      button.innerHTML = `<strong>${escapeHtml(payload.time)}</strong><span>${escapeHtml(payload.title)}</span>`;
    };
    viewButtons.forEach((button) => {
      button.addEventListener('click', () => {
        const view = button.dataset.calendarView;
        viewButtons.forEach((item) => item.classList.toggle('is-active', item === button));
        panels.forEach((panel) => panel.classList.toggle('is-active', panel.dataset.calendarPanel === view));
        if (heading) {
          heading.textContent = view === 'month' ? 'Maio 2026' : view === 'week' ? 'Semana de 7 a 13 maio' : '7 de maio de 2026';
        }
      });
    });
    calendarPage.querySelector('[data-event-create]')?.addEventListener('click', () => openEventModal());
    calendarPage.querySelector('[data-event-close]')?.addEventListener('click', () => modal.classList.remove('is-open'));
    calendarPage.addEventListener('click', (event) => {
      const eventButton = event.target.closest('[data-calendar-event]');
      if (eventButton) {
        openEventModal(eventButton);
      }
    });
    form?.addEventListener('submit', (event) => {
      event.preventDefault();
      const formData = new FormData(form);
      const payload = Object.fromEntries(formData.entries());
      const targetDay = calendarPage.querySelector(`[data-calendar-day="${payload.date}"] [data-calendar-dropzone]`);
      const existingEvents = payload.event_id
        ? [...calendarPage.querySelectorAll('[data-calendar-event]')].filter((eventButton) => eventButton.dataset.eventId === payload.event_id)
        : [];
      persistCalendarEvent(payload);
      if (existingEvents.length) {
        existingEvents.forEach((eventButton) => updateEventButton(eventButton, payload));
      } else if (targetDay) {
        targetDay.appendChild(createEventButton(payload));
      }
      modal.classList.remove('is-open');
    });
    calendarPage.addEventListener('dragstart', (event) => {
      const eventButton = event.target.closest('[data-calendar-event]');
      if (!eventButton) {
        return;
      }
      draggedEvent = eventButton;
      eventButton.classList.add('is-dragging');
      event.dataTransfer.effectAllowed = 'move';
      event.dataTransfer.setData('text/plain', eventButton.dataset.eventId);
    });
    calendarPage.addEventListener('dragend', () => {
      draggedEvent?.classList.remove('is-dragging');
      draggedEvent = null;
      calendarPage.querySelectorAll('[data-calendar-dropzone]').forEach((zone) => zone.classList.remove('is-over'));
    });
    calendarPage.addEventListener('dragover', (event) => {
      const dropzone = event.target.closest('[data-calendar-dropzone]');
      if (!dropzone || !draggedEvent) {
        return;
      }
      event.preventDefault();
      dropzone.classList.add('is-over');
    });
    calendarPage.addEventListener('dragleave', (event) => {
      const dropzone = event.target.closest('[data-calendar-dropzone]');
      if (dropzone && !dropzone.contains(event.relatedTarget)) {
        dropzone.classList.remove('is-over');
      }
    });
    calendarPage.addEventListener('drop', (event) => {
      const dropzone = event.target.closest('[data-calendar-dropzone]');
      const day = event.target.closest('[data-calendar-day]');
      if (!dropzone || !draggedEvent || !day) {
        return;
      }
      event.preventDefault();
      dropzone.classList.remove('is-over');
      dropzone.appendChild(draggedEvent);
      draggedEvent.dataset.eventDate = day.dataset.calendarDay;
      persistCalendarEvent({
        event_id: draggedEvent.dataset.eventId,
        title: draggedEvent.dataset.eventTitle,
        date: day.dataset.calendarDay,
        time: draggedEvent.dataset.eventTime,
        category: draggedEvent.dataset.eventCategory,
        client: draggedEvent.dataset.eventClient,
        location: draggedEvent.dataset.eventLocation,
      });
    });
  }
});